package com.company.snackledger.kiosk.ui;import com.company.snackledger.kiosk.api.*;import com.company.snackledger.kiosk.api.Dto.*;import com.company.snackledger.kiosk.config.KioskConfig;import javax.swing.*;import java.awt.*;import java.util.*;public class KioskFrame extends JFrame{private final KioskApiClient api;private final KioskConfig config;private final Cart cart=new Cart();private UserDto user;private final JTextField scanner=new JTextField();private final JTextArea status=new JTextArea();public KioskFrame(KioskConfig c){super("SnackLedger Kiosk");config=c;api=new KioskApiClient(c);setDefaultCloseOperation(EXIT_ON_CLOSE);setSize(900,650);setLayout(new BorderLayout());var buttons=new JPanel();for(String b:List.of("Select User","Finish Purchase","Clear Cart","Cancel","Retry Connection")){var btn=new JButton(b);btn.setFont(btn.getFont().deriveFont(22f));buttons.add(btn);if(b.equals("Finish Purchase"))btn.addActionListener(e->finish());if(b.equals("Clear Cart"))btn.addActionListener(e->{cart.clearForNewPurchase();refresh("Cart cleared");});if(b.equals("Cancel"))btn.addActionListener(e->reset());if(b.equals("Retry Connection"))btn.addActionListener(e->health());if(b.equals("Select User"))btn.addActionListener(e->manualUser());}scanner.addActionListener(e->scan(scanner.getText().trim()));add(new JLabel("Scan Badge or Select Your Name",SwingConstants.CENTER),BorderLayout.NORTH);add(new JScrollPane(status),BorderLayout.CENTER);add(scanner,BorderLayout.SOUTH);add(buttons,BorderLayout.EAST);if(c.fullscreen())setExtendedState(MAXIMIZED_BOTH);health();focusScanner();}private void focusScanner(){scanner.setText("");scanner.requestFocusInWindow();}private void health(){try{refresh("Server "+api.health().status());}catch(Exception e){refresh("Unable to connect to server: "+e.getMessage());}}private void scan(String v){try{if(user==null){user=api.badge(v);refresh("Selected "+user.displayName()+" balance "+user.balance());}else{cart.add(api.barcode(v));refresh("Added item. Total: "+cart.total());}}catch(Exception e){refresh("Scan error: "+e.getMessage());}finally{focusScanner();}}private void manualUser(){String q=JOptionPane.showInputDialog(this,"Search user");if(q==null)return;try{var users=api.users(q);if(!users.isEmpty()){user=users.get(0);refresh("Selected "+user.displayName());}}catch(Exception e){refresh("User search failed: "+e.getMessage());}}private void finish(){if(user==null||cart.lines().isEmpty()){refresh("Select a user and scan items first");return;}try{var req=new PurchaseRequest(cart.requestId(),config.kioskId(),user.id(),cart.lines().stream().map(l->new PurchaseItem(l.item().id(),l.quantity())).toList());var res=api.purchase(req);refresh("Purchase completed. Total "+res.purchaseTotal()+" previous "+res.previousBalance()+" new "+res.newBalance());new javax.swing.Timer(config.resetSeconds()*1000,e->reset()).start();}catch(java.net.http.HttpTimeoutException e){refresh("Purchase status unknown. Keep cart and retry with same request ID: "+cart.requestId());}catch(Exception e){refresh("Purchase failed: "+e.getMessage());}}private void reset(){user=null;cart.clearForNewPurchase();refresh("Ready for next user");focusScanner();}private void refresh(String m){status.append(new Date()+" - "+m+"\n");}}
